import (
	"context"
	"fmt"

	"github.com/jrswab/axe/internal/provider"
)

// Router routes MCP tool calls to owning clients.
type Router struct {
	tools map[string]*Client
}

// NewRouter returns a new empty MCP tool router.
func NewRouter() *Router {
	return &Router{tools: map[string]*Client{}}
}

// Register adds tool routes for a client and returns tools not skipped.
func (r *Router) Register(client *Client, tools []provider.Tool, builtinNames map[string]bool) ([]provider.Tool, error) {
	filtered := make([]provider.Tool, 0, len(tools))
	for _, tool := range tools {
		if builtinNames[tool.Name] {
			continue
		}

		if existing, ok := r.tools[tool.Name]; ok && existing != client {
			return nil, fmt.Errorf("MCP tool %q collision between servers %q and %q", tool.Name, existing.Name(), client.Name())
		}

		r.tools[tool.Name] = client
		filtered = append(filtered, tool)
	}

	return filtered, nil
}

// Dispatch routes a tool call to the correct MCP client.
func (r *Router) Dispatch(ctx context.Context, call provider.ToolCall) (provider.ToolResult, error) {
	client, ok := r.tools[call.Name]
	if !ok {
		return provider.ToolResult{}, fmt.Errorf("unknown MCP tool %q", call.Name)
	}
	return client.CallTool(ctx, call)
}

// Has reports whether the router has a route for the given tool name.
func (r *Router) Has(name string) bool {
	_, ok := r.tools[name]
	return ok
}

// ServerName returns the MCP server name that owns a tool.
func (r *Router) ServerName(name string) (string, bool) {
	client, ok := r.tools[name]
	if !ok {
		return "", false
	}
	return client.Name(), true
}

// Close closes each unique client once.
func (r *Router) Close() error {
	closed := map[*Client]struct{}{}
	var firstErr error

	for _, client := range r.tools {
		if _, seen := closed[client]; seen {
			continue
		}
		closed[client] = struct{}{}
		if err := client.Close(); err != nil && firstErr == nil {
			firstErr = err
		}
	}

	return firstErr
}

package mcpclient

import (
	"context"
	"errors"
	"strings"
	"sync/atomic"
	"testing"

	"github.com/jrswab/axe/internal/provider"
)

func TestRouter_RegisterAndDispatch(t *testing.T) {
	ts := newMCPStreamableServer(t)
	client := mustConnectTestClient(t, ts.URL)
	tools, err := client.ListTools(context.Background())
	if err != nil {
		t.Fatalf("ListTools failed: %v", err)
	}

	r := NewRouter()
	filtered, err := r.Register(client, tools, map[string]bool{})
	if err != nil {
		t.Fatalf("Register failed: %v", err)
	}
	if len(filtered) != len(tools) {
		t.Fatalf("filtered len = %d, want %d", len(filtered), len(tools))
	}

	result, err := r.Dispatch(context.Background(), provider.ToolCall{ID: "1", Name: "success"})
	if err != nil {
		t.Fatalf("Dispatch failed: %v", err)
	}
	if result.Content != "ok" {
		t.Fatalf("content = %q, want ok", result.Content)
	}
}

func TestRouter_Has_UnknownTool(t *testing.T) {
	r := NewRouter()
	if r.Has("missing") {
		t.Fatal("expected Has to return false")
	}
}

func TestRouter_Dispatch_UnknownTool(t *testing.T) {
	r := NewRouter()
	_, err := r.Dispatch(context.Background(), provider.ToolCall{ID: "1", Name: "missing"})
	if err == nil {
		t.Fatal("expected error, got nil")
	}
	if !strings.Contains(err.Error(), `unknown MCP tool`) {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestRouter_Register_SkipsBuiltins(t *testing.T) {
	ts := newMCPStreamableServer(t)
	client := mustConnectTestClient(t, ts.URL)
	tools, err := client.ListTools(context.Background())
	if err != nil {
		t.Fatalf("ListTools failed: %v", err)
	}

	r := NewRouter()
	filtered, err := r.Register(client, tools, map[string]bool{"success": true})
	if err != nil {
		t.Fatalf("Register failed: %v", err)
	}
	if len(filtered) != len(tools)-1 {
		t.Fatalf("filtered len = %d, want %d", len(filtered), len(tools)-1)
	}
	if r.Has("success") {
		t.Fatal("expected built-in tool to be skipped")
	}
}

func TestRouter_Register_MCPCollision(t *testing.T) {
	ts1 := newMCPStreamableServer(t)
	client1, err := Connect(context.Background(), agentTestConfig("one", ts1.URL))
	if err != nil {
		t.Fatalf("Connect client1 failed: %v", err)
	}
	t.Cleanup(func() { _ = client1.Close() })
	tools1, err := client1.ListTools(context.Background())
	if err != nil {
		t.Fatalf("ListTools client1 failed: %v", err)
	}

	ts2 := newMCPStreamableServer(t)
	client2, err := Connect(context.Background(), agentTestConfig("two", ts2.URL))
	if err != nil {
		t.Fatalf("Connect client2 failed: %v", err)
	}
	t.Cleanup(func() { _ = client2.Close() })
	tools2, err := client2.ListTools(context.Background())
	if err != nil {
		t.Fatalf("ListTools client2 failed: %v", err)
	}

	r := NewRouter()
	if _, err := r.Register(client1, tools1, map[string]bool{}); err != nil {
		t.Fatalf("Register client1 failed: %v", err)
	}
	_, err = r.Register(client2, tools2, map[string]bool{})
	if err == nil {
		t.Fatal("expected collision error, got nil")
	}
	if !strings.Contains(err.Error(), `collision`) || !strings.Contains(err.Error(), `"one"`) || !strings.Contains(err.Error(), `"two"`) {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestRouter_Close_ClosesAllClients(t *testing.T) {
	r := NewRouter()
	var closed int32
	r.tools["a"] = &Client{name: "a", closeFn: func() error { atomic.AddInt32(&closed, 1); return nil }}
	r.tools["b"] = &Client{name: "b", closeFn: func() error { atomic.AddInt32(&closed, 1); return nil }}

	if err := r.Close(); err != nil {
		t.Fatalf("Close failed: %v", err)
	}
	if got := atomic.LoadInt32(&closed); got != 2 {
		t.Fatalf("close count = %d, want 2", got)
	}
}

func TestRouter_Close_DeduplicatesClients(t *testing.T) {
	r := NewRouter()
	var closed int32
	shared := &Client{name: "shared", closeFn: func() error { atomic.AddInt32(&closed, 1); return nil }}
	r.tools["a"] = shared
	r.tools["b"] = shared

	if err := r.Close(); err != nil {
		t.Fatalf("Close failed: %v", err)
	}
	if got := atomic.LoadInt32(&closed); got != 1 {
		t.Fatalf("close count = %d, want 1", got)
	}
}

func TestRouter_Close_ReturnsFirstError(t *testing.T) {
	r := NewRouter()
	errBoom := errors.New("boom")
	r.tools["a"] = &Client{name: "a", closeFn: func() error { return errBoom }}
	r.tools["b"] = &Client{name: "b", closeFn: func() error { return nil }}

	err := r.Close()
	if err == nil {
		t.Fatal("expected error, got nil")
	}
	if !errors.Is(err, errBoom) {
		t.Fatalf("got %v, want %v", err, errBoom)
	}
}

