		t.Errorf("got %q, want %q", err.Error(), want)
	}
}

func TestValidate_MissingName(t *testing.T) {
	cfg := &AgentConfig{Model: "anthropic/claude-sonnet-4-20250514"}
	err := Validate(cfg)
