	}
	want := "agent config missing required field: model"
	if err.Error() != want {
		t.Errorf("got %q, want %q", err.Error(), want)
	}
}

// --- Phase 5: List tests ---

func TestList_EmptyDirectory(t *testing.T) {
	_ = setupAgentsDir(t) // creates empty agents/

	agents, err := List()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(agents) != 0 {
