)

func main() {
	ctx := context.Background()

	transport := &mcp.StreamableClientTransport{
		Endpoint: "http://localhost:8080/mcp",
	}

	client, err := mcp.Connect(ctx, transport, &mcp.ClientOptions{
		// Add any necessary client options here
	})

	if err != nil {
		log.Fatalf("Failed to connect to MCP server: %v", err)
	}

	log.Println("Successfully connected to MCP server.")

	// Use the client to interact with the server
	defer client.Close()
}

```

--------------------------------

### HTTP Transport for MCP in Go

Source: https://context7.com/modelcontextprotocol/go-sdk/llms.txt

Demonstrates using HTTP-based transport for MCP communication. It includes setting up an MCP server with `StreamableHTTPHandler` and a client with `StreamableClientTransport`. This allows for communication over HTTP endpoints.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"net/http"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

func main() {
	// Server setup
	server := mcp.NewServer(&mcp.Implementation{Name: "http-server", Version: "v1.0.0"}, nil)

	mcp.AddTool(server, &mcp.Tool{Name: "ping"}, func(ctx context.Context, req *mcp.CallToolRequest, _ struct{}) (*mcp.CallToolResult, any, error) {
		return &mcp.CallToolResult{
			Content: []mcp.Content{&mcp.TextContent{Text: "pong"}},
		}, nil, nil
	})

	handler := mcp.NewStreamableHTTPHandler(func(r *http.Request) *mcp.Server {
		return server
	}, nil)

	go http.ListenAndServe(":8080", handler)

	// Client setup
	client := mcp.NewClient(&mcp.Implementation{Name: "http-client", Version: "v1.0.0"}, nil)
	transport := &mcp.StreamableClientTransport{
		Endpoint: "http://localhost:8080",
	}

	session, err := client.Connect(context.Background(), transport, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer session.Close()

	result, _ := session.CallTool(context.Background(), &mcp.CallToolParams{Name: "ping"})
	fmt.Println(result.Content[0].(*mcp.TextContent).Text)
	// Output: pong
}
```

--------------------------------

### Create MCP Client in Go

Source: https://context7.com/modelcontextprotocol/go-sdk/llms.txt

Illustrates how to create an MCP client using `mcp.NewClient`. This client can connect to MCP servers and invoke capabilities via a session. The example connects to a server using a command transport and calls the 'greet' tool.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"os/exec"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

func main() {
	ctx := context.Background()

	// Create client with implementation info
	client := mcp.NewClient(&mcp.Implementation{
		Name:    "my-client",
		Version: "v1.0.0",
	}, nil)

	// Connect to server via command transport (stdio)
	transport := &mcp.CommandTransport{
		Command: exec.Command("./my-mcp-server"),
	}
	session, err := client.Connect(ctx, transport, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer session.Close()

	// Call a tool
	result, err := session.CallTool(ctx, &mcp.CallToolParams{
		Name:      "greet",
		Arguments: map[string]any{"name": "World"},
	})
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println(result.Content[0].(*mcp.TextContent).Text)
	// Output: Hello, World!
}
```

--------------------------------

### Connect and Call Tool with MCP Client in Go

Source: https://github.com/modelcontextprotocol/go-sdk/blob/main/README.md

Illustrates how to create an MCP client in Go and connect to a server running over standard input/output. It then demonstrates calling a 'greet' tool on the server and logging the response. This requires the 'mcp' package and standard library packages like 'os/exec'.

```go
package main

import (
	"context"
	"log"
	"os/exec"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

func main() {
	ctx := context.Background()

	// Create a new client, with no features.
	client := mcp.NewClient(&mcp.Implementation{Name: "mcp-client", Version: "v1.0.0"}, nil)

	// Connect to a server over stdin/stdout.
	transport := &mcp.CommandTransport{Command: exec.Command("myserver")}
	session, err := client.Connect(ctx, transport, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer session.Close()

	// Call a tool on the server.
	params := &mcp.CallToolParams{
		Name:      "greet",
		Arguments: map[string]any{"name": "you"},
	}
	res, err := session.CallTool(ctx, params)
	if err != nil {
		log.Fatalf("CallTool failed: %v", err)
	}
	if res.IsError {
		log.Fatal("tool failed")
	}
	for _, c := range res.Content {
		log.Print(c.(*mcp.TextContent).Text)
	}
}
```

