func TestLoad_ValidConfig(t *testing.T) {
	agentsDir := setupAgentsDir(t)

	tomlContent := `
name = "full-agent"
description = "A full test agent"
model = "anthropic/claude-sonnet-4-20250514"
system_prompt = "You are helpful."
skill = "skills/sample/SKILL.md"
