workdir = "/tmp/work"
sub_agents = ["helper", "reviewer"]

[memory]
enabled = true
path = "/tmp/memory"

[params]
temperature = 0.7
max_tokens = 4096
`
	writeAgentFile(t, agentsDir, "full-agent", tomlContent)

	cfg, err := Load("full-agent")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if cfg.Name != "full-agent" {
		t.Errorf("Name = %q, want %q", cfg.Name, "full-agent")
